package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine;

import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractSimpleQueryModelVisitor;

/**
 * Simple risk-adjusted cost model.
 */
public final class DefaultCostModel implements CostModel {

	@Override
	public Cost cost(TupleExpr joinTree, JoinOptimizationContext ctx) {
		Estimate root = ctx.getEstimator().estimateRows(joinTree, ctx);
		RiskCollector collector = new RiskCollector(ctx);
		joinTree.visit(collector);
		double aggregatedRisk = aggregateRisk(root.getRisk(), collector.getAggregateRisk());
		double expectedMillis = Math.max(1.0d, root.getRows() + collector.getEstimatedWork());
		double score = expectedMillis * (1.0d + ctx.getConfig().getRiskPenaltyWeight() * aggregatedRisk);
		return new Cost(expectedMillis, aggregatedRisk, score, root.getRows());
	}

	private double aggregateRisk(double rootRisk, double pathRisk) {
		double boundedRoot = Math.max(0.0d, Math.min(1.0d, rootRisk));
		double boundedPath = Math.max(0.0d, Math.min(1.0d, pathRisk));
		return 1.0d - ((1.0d - boundedRoot) * (1.0d - boundedPath));
	}

	private static final class RiskCollector extends AbstractSimpleQueryModelVisitor<RuntimeException> {

		private final JoinOptimizationContext ctx;
		private double aggregateRisk;
		private double estimatedWork;

		private RiskCollector(JoinOptimizationContext ctx) {
			super(true);
			this.ctx = ctx;
		}

		@Override
		public void meet(Join node) {
			Estimate estimate = ctx.getEstimator().estimateRows(node, ctx);
			aggregateRisk = 1.0d - ((1.0d - aggregateRisk) * (1.0d - estimate.getRisk()));
			estimatedWork += estimate.getRows();
			super.meet(node);
		}

		private double getAggregateRisk() {
			return aggregateRisk;
		}

		private double getEstimatedWork() {
			return estimatedWork;
		}
	}
}
